  INTP: "„ლოგიკოსი“ – ძლიერი ლოგიკური აზროვნებითა და ინტელექტუალური ცნობისმოყვარეობით გამოირჩევიან. მშვიდი და თავშეკავებული ბუნების მიუხედავად, ღრმად აანალიზებენ იდეებს და სიამოვნებას იღებენ ახალი ცოდნის აღმოჩენით."
};

export default function FinalResults({ results }) {
  const [user, setUser] = useState(false);
  const [savedResults, setSavedResults] = useState(
    JSON.parse(localStorage.getItem("savedResults")) || []
  );
  const [type, setType] = useState("");
  const [articles, setArticles] = useState([]);
  const location = useLocation();

  // =========================
  // ტიპის გამოთვლა
  // =========================
  useEffect(() => {
    if (localStorage.getItem("auth_token")) setUser(true);

    let calculated =
      (results?.EI || "") +
      (results?.SN || "") +
      (results?.TF || "") +
      (results?.JP || "");

    if (!calculated || calculated.length !== 4) {
      const params = new URLSearchParams(location.search);
      calculated = params.get("type") || "";
    }

    if (!calculated || calculated.length !== 4) {
      calculated = localStorage.getItem("pendingResult") || "";
    }

    if (calculated.length === 4) {
      setType(calculated.toUpperCase());
      localStorage.setItem("pendingResult", calculated.toUpperCase());
    }
  }, [results, location]);

  // =========================
  // სტატიების წამოღება
  // =========================
  useEffect(() => {
    if (!type) return;

    fetch(`http://localhost:5000/api/articles?type=${type}`)
      .then(res => res.json())
      .then(data => {
        setArticles(data || []);
      })
      .catch(() => setArticles([]));
  }, [type]);

  // =========================
  // ავტო სკროლი sidebar
  // =========================
  useEffect(() => {
    if (articles.length < 2) return;

    const sidebar = document.querySelector(".articles-sidebar");
    if (!sidebar) return;

    const scrollStep = 80; // თითოეული სტატიის სიმაღლე
    const interval = setInterval(() => {
      if (sidebar.scrollTop + sidebar.clientHeight >= sidebar.scrollHeight) {
        sidebar.scrollTop = 0;
      } else {
        sidebar.scrollTop += scrollStep;
      }
    }, 4000);

    return () => clearInterval(interval);
  }, [articles]);

  // =========================
  // შენახვა
  // =========================
  const toggleSave = () => {
    if (!type) return;
    let saved = [...savedResults];

    if (!saved.includes(type)) {
      if (saved.length >= 1) saved.shift();
      saved.push(type);
    }

    localStorage.setItem("savedResults", JSON.stringify(saved));
    setSavedResults(saved);
  };

  if (!type) return <p>Loading...</p>;

  return (
    <div className="result-layout">
      <div className="register-page">
        <div className="register-card">

          {user && (
            <img
              src={savedResults.includes(type) ? "/save1.png" : "/save.png"}
              className="save-icon-result"
              onClick={toggleSave}
              alt="save"
            />
          )}

          <img
            className="result-image"
            src={`/images/types/${type.toUpperCase()}.png`}
            alt={type}
          />

          <h2 className="register-title">{type}</h2>
          <p className="register-description">{typeDescriptions[type]}</p>

          {!user && (
            <p className="register-text">
              მონაცემების შესანახად{" "}
              <Link
                to="/register"
                className="register-link"
                onClick={() => localStorage.setItem("pendingResult", type)}
              >
                გაიარე რეგისტრაცია
              </Link>
            </p>
          )}
        </div>
      </div>

      {articles.length > 0 && (
        <div className="articles-sidebar">
          <h3 className="sidebar-title">
            გაიცანი შენი ფსიქოტიპი უკეთ
            <span className="overview-link-wrap">
              <Link to={`/ArticlesPage?q=${type}`} className="overview-link">
                გადადი მიმოხილვებზე
    </Link>
            </span>
          </h3>

          {articles.map(a => (
            <Link key={a.slug} to={`/articles/${a.slug}`} className="article-card">
              <img
                className="article-thumb"
                alt={a.title}
                src={
                  a.image
                    ? `http://localhost:5000/images/${a.image.replace(/^\//, "")}`
                    : "/images/articles/default.jpg"
                }
                onError={e => { e.target.src = "/images/articles/default.jpg"; }}
              />
              <div className="article-info">
                <b>{a.title}</b>
                <p>{a.excerpt}</p>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
